<?php

/**
 * Hand-written code. NOT generated by Speakeasy. Safe from regeneration.
 *
 * @see docs/REGENERATION.md
 */

declare(strict_types=1);

namespace Factuarea\Sdk\Custom\Pagination;

use Psr\Http\Message\ResponseInterface;

/**
 * Universal cursor auto-paginator for Factuarea list endpoints.
 *
 * Every Factuarea listing returns the canonical cursor envelope:
 *
 * ```json
 * { "data": [ ... ], "has_more": true, "next_cursor": "inv_abc123" }
 * ```
 *
 * paged through with the `starting_after` query parameter (or `cursor` on the
 * overdue/pending purchase-invoice listings). This helper turns any such listing
 * into a lazy iterator over the individual items across ALL pages, so callers
 * never manage cursors by hand:
 *
 * ```php
 * use Factuarea\Sdk\Custom\Pagination\PageIterator;
 *
 * $pages = new PageIterator(
 *     fn (?string $cursor) => $sdk->invoices->publicApiV1InvoicesList(
 *         new Operations\PublicApiV1InvoicesListRequest(startingAfter: $cursor),
 *     )->rawResponse,
 * );
 *
 * foreach ($pages->items() as $invoice) {
 *     // $invoice is one element of "data", decoded as an associative array
 * }
 * ```
 *
 * Pagination relies on the raw JSON response body, which makes it work for every
 * listing regardless of the typed page model the generator produced — the
 * envelope shape (`data` / `has_more` / `next_cursor`) is identical across the
 * whole API surface.
 *
 * @phpstan-type Fetcher callable(?string): ResponseInterface
 */
final class PageIterator
{
    /** @var callable(?string): ResponseInterface */
    private $fetcher;

    private string $dataKey;

    private string $cursorKey;

    private string $hasMoreKey;

    /**
     * @param  callable(?string): ResponseInterface  $fetcher  Returns the raw HTTP response
     *         for the page starting after the given cursor (null for the first page).
     * @param  string  $dataKey  JSON key holding the array of items.
     * @param  string  $cursorKey  JSON key holding the cursor for the next page.
     * @param  string  $hasMoreKey  JSON key signalling whether more pages exist.
     */
    public function __construct(
        callable $fetcher,
        string $dataKey = 'data',
        string $cursorKey = 'next_cursor',
        string $hasMoreKey = 'has_more',
    ) {
        $this->fetcher = $fetcher;
        $this->dataKey = $dataKey;
        $this->cursorKey = $cursorKey;
        $this->hasMoreKey = $hasMoreKey;
    }

    /**
     * Lazily yield each item across every page.
     *
     * @return \Generator<int, mixed>
     */
    public function items(): \Generator
    {
        foreach ($this->pages() as $page) {
            $items = $page[$this->dataKey] ?? [];
            if (! is_array($items)) {
                continue;
            }
            foreach ($items as $item) {
                yield $item;
            }
        }
    }

    /**
     * Lazily yield each page as a decoded associative array.
     *
     * @return \Generator<int, array<string, mixed>>
     */
    public function pages(): \Generator
    {
        $cursor = null;

        do {
            $response = ($this->fetcher)($cursor);
            /** @var array<string, mixed> $page */
            $page = json_decode((string) $response->getBody(), true, 512, JSON_THROW_ON_ERROR);

            yield $page;

            $hasMore = (bool) ($page[$this->hasMoreKey] ?? false);
            $next = $page[$this->cursorKey] ?? null;
            $cursor = is_string($next) && $next !== '' ? $next : null;
        } while ($hasMore && $cursor !== null);
    }

    /**
     * Eagerly collect every item across all pages into a single array.
     *
     * Use with care on large datasets — prefer {@see items()} for streaming.
     *
     * @return list<mixed>
     */
    public function all(): array
    {
        return iterator_to_array($this->items(), false);
    }
}
